 1→import { useState } from "react";
 2→import styled from "@emotion/styled";
 3→import { Button } from "@leafygreen-ui/button";
 4→import { palette } from "@leafygreen-ui/palette";
 5→import { TextInput } from "@leafygreen-ui/text-input";
 6→import { Location, Navigate, useLocation } from "react-router-dom";
 7→import { FullPageLoad } from "../../components/FullPageLoad";
 8→import { size } from "../../constants/tokens";
 9→import { useAuthProviderContext } from "../../context/AuthProvider";
10→
11→const { green } = palette;
12→
13→const getReferrer = (location: Location): string => {
14→  const state = location.state as { referrer?: string };
15→  return state?.referrer ?? "/";
16→};
17→interface LoginPageProps {
18→  /**
19→   * If `ignoreAuthCheck` is true, the component will render without checking the user's authentication status.
20→   * This is useful for test environments where the user's authentication status is not relevant.
21→   */
22→  ignoreAuthCheck?: boolean;
23→}
24→const LoginPage: React.FC<LoginPageProps> = ({ ignoreAuthCheck }) => {
25→  const location = useLocation();
26→  const { hasCheckedAuth, isAuthenticated, localLogin } =
27→    useAuthProviderContext();
28→
29→  const [username, setUsername] = useState("");
30→  const [password, setPassword] = useState("");
31→
32→  if (!hasCheckedAuth && !ignoreAuthCheck) {
33→    return <FullPageLoad />;
34→  }
35→  return isAuthenticated ? (
36→    <Navigate to={getReferrer(location)} />
37→  ) : (
38→    <PageWrapper>
39→      <LoginForm
40→        onSubmit={(e) => {
41→          e.preventDefault();
42→          localLogin({ password, username });
43→        }}
44→      >
45→        <TextInput
46→          data-cy="login-username"
47→          label="Username"
48→          onChange={(e) => setUsername(e.target.value)}
49→          type="text"
50→          value={username}
51→        />
52→        <TextInput
53→          data-cy="login-password"
54→          label="Password"
55→          onChange={(e) => setPassword(e.target.value)}
56→          type="password"
57→          value={password}
58→        />
59→        <StyledButton
60→          data-cy="login-submit"
61→          onClick={() => localLogin({ password, username })}
62→          type="submit"
63→          variant="baseGreen"
64→        >
65→          Login
66→        </StyledButton>
67→      </LoginForm>
68→    </PageWrapper>
69→  );
70→};
71→
72→const PageWrapper = styled.div`
73→  width: 100vw;
74→  height: 100vh;
75→  display: flex;
76→  align-items: center;
77→  justify-content: center;
78→`;
79→
80→const LoginForm = styled.form`
81→  display: flex;
82→  flex-direction: column;
83→  justify-content: center;
84→  gap: ${size.s};
85→
86→  width: 400px;
87→  padding: ${size.l} ${size.m};
88→  background-color: ${green.light3};
89→  border-radius: ${size.m};
90→`;
91→
92→const StyledButton = styled(Button)`
93→  align-self: flex-end;
94→`;
