  1→import { useEffect, useRef, useState } from "react";
  2→import styled from "@emotion/styled";
  3→import { Button } from "@leafygreen-ui/button";
  4→import { Tooltip, TooltipProps, Align, Justify } from "@leafygreen-ui/tooltip";
  5→import { size } from "../../constants/tokens";
  6→import { wordBreakCss } from "../styles";
  7→
  8→export { Align, Justify };
  9→
 10→type PopconfirmProps = Omit<
 11→  TooltipProps,
 12→  "onEnter" | "onEntering" | "onEntered" | "onExit" | "onExited" | "onExiting"
 13→> & {
 14→  confirmDisabled?: boolean;
 15→  confirmText?: string;
 16→  "data-cy"?: string;
 17→  onConfirm?: (e?: React.MouseEvent) => void;
 18→  children: React.ReactNode;
 19→};
 20→
 21→const Popconfirm: React.FC<PopconfirmProps> = ({
 22→  children,
 23→  confirmDisabled = false,
 24→  confirmText = "Yes",
 25→  onClose = () => {},
 26→  onConfirm = () => {},
 27→  open: controlledOpen,
 28→  refEl,
 29→  setOpen: controlledSetOpen,
 30→  ...props
 31→}) => {
 32→  const isControlled = !!(controlledOpen !== undefined && controlledSetOpen);
 33→  const [uncontrolledOpen, uncontrolledSetOpen] = useState(false);
 34→  const open = isControlled ? controlledOpen : uncontrolledOpen;
 35→  const setOpen = isControlled ? controlledSetOpen : uncontrolledSetOpen;
 36→
 37→  const popoverRef = useRef<HTMLDivElement>(null);
 38→
 39→  useEffect(() => {
 40→    const handleClickOutside = (event: MouseEvent) => {
 41→      if (
 42→        popoverRef.current &&
 43→        !popoverRef.current.contains(event.target as Node) &&
 44→        (!refEl ||
 45→          (refEl &&
 46→            refEl instanceof HTMLElement &&
 47→            refEl.contains(event.target as Node)))
 48→      ) {
 49→        onClose();
 50→        setOpen(false);
 51→      }
 52→    };
 53→
 54→    if (typeof window !== "undefined" && open) {
 55→      document.addEventListener("mousedown", handleClickOutside);
 56→      return () => {
 57→        document.removeEventListener("mousedown", handleClickOutside);
 58→      };
 59→    }
 60→  }, [open, onClose, setOpen, refEl]);
 61→
 62→  return (
 63→    <Tooltip
 64→      onClose={onClose}
 65→      open={open}
 66→      refEl={refEl}
 67→      setOpen={setOpen}
 68→      triggerEvent="click"
 69→      {...props}
 70→    >
 71→      <ContentWrapper ref={popoverRef}>
 72→        {children}
 73→        <ButtonWrapper>
 74→          <Button
 75→            as="button"
 76→            onClick={() => {
 77→              onClose();
 78→              setOpen(false);
 79→            }}
 80→            size="small"
 81→          >
 82→            Cancel
 83→          </Button>
 84→          <Button
 85→            as="button"
 86→            disabled={confirmDisabled}
 87→            onClick={(e) => {
 88→              onConfirm(e);
 89→              setOpen(false);
 90→            }}
 91→            size="small"
 92→            variant="primary"
 93→          >
 94→            {confirmText}
 95→          </Button>
 96→        </ButtonWrapper>
 97→      </ContentWrapper>
 98→    </Tooltip>
 99→  );
100→};
101→
102→const ContentWrapper = styled.div`
103→  display: flex;
104→  flex-direction: column;
105→  gap: ${size.xs};
106→
107→  ${wordBreakCss}
108→`;
109→
110→const ButtonWrapper = styled.div`
111→  display: flex;
112→  align-self: flex-end;
113→  margin-top: ${size.xs};
114→  gap: ${size.xxs};
115→`;
116→
117→export default Popconfirm;
