 1→import styled from "@emotion/styled";
 2→import { Button } from "@leafygreen-ui/button";
 3→import { Disclaimer } from "@leafygreen-ui/typography";
 4→import { size } from "../../constants/tokens";
 5→import usePagination from "../../hooks/usePagination";
 6→import Icon from "../Icon";
 7→
 8→interface Props {
 9→  countLimit?: number;
10→  currentPage: number;
11→  onChange?: (i: number) => void;
12→  totalResults: number;
13→  pageSize: number;
14→}
15→
16→/**
17→ * Pagination component for navigating between pages of data
18→ * By default it will update the page query param in the URL
19→ * @param props - React props passed to the component
20→ * @param props.countLimit - optional count for the max value that was queried for. Used to display "many" instead of an exact number
21→ * @param props.currentPage - the current page
22→ * @param props.onChange - optional callback for when the page changes (Will override the default behavior of updating the URL query param)
23→ * @param props.totalResults - total number of results
24→ * @param props.pageSize - maximum number of results per page
25→ * @returns The Pagination component
26→ */
27→const Pagination: React.FC<Props> = ({
28→  countLimit,
29→  currentPage,
30→  onChange,
31→  pageSize,
32→  totalResults,
33→}) => {
34→  const { setPage } = usePagination();
35→  const handleChange = onChange || setPage;
36→  const numPages = Math.ceil(totalResults / pageSize);
37→
38→  const handlePrevClick = () => {
39→    handleChange(currentPage - 1);
40→  };
41→  const handleNextClick = () => {
42→    handleChange(currentPage + 1);
43→  };
44→
45→  const denominator =
46→    countLimit && totalResults >= countLimit ? "many" : numPages;
47→
48→  return (
49→    <Container data-cy="pagination">
50→      <StyledButton
51→        data-cy="prev-page-button"
52→        disabled={currentPage === 0}
53→        leftGlyph={<Icon glyph="ChevronLeft" size="small" />}
54→        onClick={handlePrevClick}
55→        size="small"
56→      />
57→      <PageLabel>
58→        <Disclaimer>
59→          {numPages > 0 ? currentPage + 1 : 0} / {denominator}
60→        </Disclaimer>
61→      </PageLabel>
62→      <StyledButton
63→        data-cy="next-page-button"
64→        disabled={numPages === 0 || currentPage === numPages - 1}
65→        leftGlyph={<Icon glyph="ChevronRight" size="small" />}
66→        onClick={handleNextClick}
67→        size="small"
68→      />
69→    </Container>
70→  );
71→};
72→
73→const StyledButton = styled(Button)`
74→  margin-right: ${size.xxs};
75→  margin-left: ${size.xxs};
76→`;
77→
78→const PageLabel = styled.div`
79→  width: 48px;
80→  text-align: center;
81→`;
82→
83→const Container = styled.div`
84→  align-items: center;
85→  display: flex;
86→  flex-shrink: 0;
87→`;
88→
89→export default Pagination;
