 4→/**
 5→ * `onChangeHandler` simplifies applying a side effect with one of react-table's callback functions (e.g. onColumnFiltersChange, onSortingChange).
 6→ * @param setState - state updater as returned by a React useState hook.
 7→ * @param sideEffect - side effect function, to be called with the updated state returned by setState.
 8→ * @returns void
 9→ */
10→export const onChangeHandler = <T>(
11→  setState: OnChangeFn<T> | Dispatch<SetStateAction<T>>,
12→  sideEffect?: (updatedState: T) => void,
13→) =>
14→  ((updater) => {
15→    setState((prev) => {
16→      const updatedState =
17→        updater instanceof Function ? updater(prev) : updater;
18→      sideEffect?.(updatedState);
19→      return updatedState;
20→    });
21→  }) satisfies OnChangeFn<T>;
