 56→const mapTaskStatusToBadgeVariant: Record<string, Variant> = {
 57→  [TaskStatus.Inactive]: Variant.LightGray,
 58→  [TaskStatus.Unstarted]: Variant.LightGray,
 59→  [TaskStatus.Undispatched]: Variant.LightGray,
 60→  [TaskStatus.Blocked]: Variant.LightGray,
 61→  [TaskStatus.Pending]: Variant.LightGray,
