 1→import { useEffect, useRef } from "react";
 2→import { ErrorLike } from "@apollo/client";
 3→import { CombinedGraphQLErrors } from "@apollo/client/errors";
 4→import { useToastContext } from "../../context/toast";
 5→
 6→/**
 7→ * useErrorToast displays an error toast when a GraphQL query fails.
 8→ * It tracks the error message to avoid showing duplicate toasts for the same error.
 9→ * @param error - The error from useQuery or useLazyQuery
10→ * @param messagePrefix - A human-readable prefix describing what failed (e.g., "Unable to load files")
11→ * @param shouldDispatchToast - An optional param to conditionally dispatch the toast. If unset, defaults to true.
12→ * @example
13→ * const { data, error } = useQuery(MY_QUERY);
14→ * useErrorToast(error, "Unable to load data");
15→ * // Shows toast: "Unable to load data: <error message>"
16→ */
17→export const useErrorToast = (
18→  error: ErrorLike | undefined,
19→  messagePrefix: string,
20→  shouldDispatchToast: boolean = true,
21→) => {
22→  const dispatchToast = useToastContext();
23→  const lastErrorMessage = useRef<string | null>(null);
24→
25→  useEffect(() => {
26→    // Only show toast if there's a new error we haven't shown yet
27→    if (
28→      error &&
29→      CombinedGraphQLErrors.is(error) &&
30→      error.message !== lastErrorMessage.current
31→    ) {
32→      lastErrorMessage.current = error.message;
33→      if (shouldDispatchToast) {
34→        dispatchToast.error(`${messagePrefix}: ${error.message}`);
35→      }
36→    }
37→    // Clear tracked error when error is resolved
38→    if (!error) {
39→      lastErrorMessage.current = null;
40→    }
41→  }, [error, messagePrefix, dispatchToast, shouldDispatchToast]);
42→};
