 1→const getLocalStorageString = (key: string): string | undefined => {
 2→  try {
 3→    return localStorage.getItem(key) ?? undefined;
 4→  } catch {
 5→    return undefined;
 6→  }
 7→};
 8→
 9→const setLocalStorageString = (key: string, value: string): void => {
10→  try {
11→    localStorage.setItem(key, value);
12→  } catch {
13→    // Silently fail if localStorage is unavailable or full.
14→  }
15→};
