17→function getLocalStorageBoolean(key: string): boolean | undefined;
18→function getLocalStorageBoolean(key: string, defaultValue: boolean): boolean;
19→
20→/**
21→ * Reads a boolean from localStorage, returning defaultValue (or undefined) if the key is absent.
22→ * @param key - The localStorage key.
23→ * @param defaultValue - Value returned when the key is absent.
24→ * @returns The stored boolean, the defaultValue, or undefined.
25→ */
26→function getLocalStorageBoolean(
27→  key: string,
28→  defaultValue?: boolean,
29→): boolean | undefined {
30→  const value = getLocalStorageString(key);
31→  if (value === undefined) return defaultValue;
32→  return value === "true";
33→}
34→
35→const setLocalStorageBoolean = (key: string, value: boolean): void => {
36→  setLocalStorageString(key, value.toString());
37→};
