119→const AnimatedAccordion = styled.div<{
120→  hide: boolean;
121→  disableAnimations: boolean;
122→}>`
123→  display: grid;
124→  grid-template-rows: ${({ hide }): string => (hide ? "0fr" : "1fr")};
125→  ${({ disableAnimations }) =>
126→    !disableAnimations &&
127→    `transition: grid-template-rows ${transitionDuration.default}ms ease;`}
128→`;
129→
130→const ContentsContainer = styled.div<{ useIndent: boolean }>`
131→  overflow: hidden;
132→  ${({ useIndent }) =>
133→    useIndent &&
134→    `
135→      margin-left: 26px;
136→
137→      /* Handle input focus borders which get cut off due to overflow: hidden */
